import fs from 'node:fs';
import path from 'node:path';
export function writeConfig(configDir, selectedAdapters) {
    fs.mkdirSync(configDir, { recursive: true });
    const configPath = path.join(configDir, 'config.toml');
    const enabled = new Set(selectedAdapters.map((adapter) => adapter.name));
    const content = `# Generated by npx agent_orb\n\n[install]\nmethod = "npx"\nversion = "0.1.0"\n\n[adapters.codex]\nenabled = ${enabled.has('codex')}\nbinary = "codex"\nwrapper = "codex-orb"\n\n[adapters.claude]\nenabled = ${enabled.has('claude')}\nbinary = "claude"\nwrapper = "claude-orb"\n\n[daemon]\nhost = "127.0.0.1"\nport = 17321\nauto_start = true\n\n[orb]\nauto_start = true\nposition = "top-right"\nsize = 36\nopacity = 0.88\nalways_on_top = true\n\n[behavior]\nsilent_threshold_seconds = 20\nstuck_threshold_seconds = 180\ncompleted_hold_seconds = 10\n\n[privacy]\ninclude_output_sample = false\nmax_sample_chars = 512\n`;
    fs.writeFileSync(configPath, content, 'utf8');
    return configPath;
}
